body.script:
(function(){
  'use strict';

  var el = document.getElementById('dashData');
  var graficoDatos  = [];
  var totalIngresos = 0;
  var totalEgresos  = 0;
  if (el) {
    try { graficoDatos  = JSON.parse(el.getAttribute('data-grafico') || '[]'); } catch(e){}
    totalIngresos = parseFloat(el.getAttribute('data-ingresos') || '0') || 0;
    totalEgresos  = parseFloat(el.getAttribute('data-egresos')  || '0') || 0;
  }

  /* ── PAGINATION + FILTER ─────────────────────────────────── */
  var PAGE_SIZE   = 20;
  var currentPage = 1;

  function getFilteredRows() {
    var search = ((document.getElementById('tableSearch') || {}).value || '').toLowerCase();
    var filter = (document.getElementById('tableFilter') || {}).value || 'all';
    var rows = document.querySelectorAll('#movTable tbody tr');
    var visible = [];
    rows.forEach(function(row) {
      var tipo = row.getAttribute('data-tipo') || '';
      var desc = row.getAttribute('data-desc') || '';
      var match = (filter === 'all' || tipo === filter) && (!search || desc.indexOf(search) !== -1);
      if (match) visible.push(row);
    });
    return visible;
  }

  function renderPage(page) {
    currentPage = page;
    var allRows   = document.querySelectorAll('#movTable tbody tr');
    var filtered  = getFilteredRows();
    var total     = filtered.length;
    var totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
    if (currentPage > totalPages) currentPage = totalPages;
    var start = (currentPage - 1) * PAGE_SIZE;
    var end   = start + PAGE_SIZE;

    /* Hide all, then show only the current page slice of filtered rows */
    allRows.forEach(function(r) { r.style.display = 'none'; });
    filtered.forEach(function(r, i) {
      r.style.display = (i >= start && i < end) ? '' : 'none';
    });

    /* Page info */
    var infoEl = document.getElementById('pageInfo');
    if (infoEl) {
      var from = total === 0 ? 0 : start + 1;
      var to   = Math.min(end, total);
      infoEl.textContent = 'Mostrando ' + from + ' - ' + to + ' de ' + total + ' registros';
    }

    /* Page buttons */
    var btnsEl = document.getElementById('pageBtns');
    if (!btnsEl) return;
    var html = [];
    var _S2 = '\x3C', _E2 = '\x3E';

    /* Prev */
    if (currentPage > 1) {
      html.push(_S2+'button class="page-btn" onclick="renderPage('+(currentPage-1)+')"'+_E2+'←'+_S2+'/button'+_E2);
    }

    /* Page numbers — show window of 5 around current */
    var winStart = Math.max(1, currentPage - 2);
    var winEnd   = Math.min(totalPages, currentPage + 2);
    if (winStart > 1) {
      html.push(_S2+'button class="page-btn" onclick="renderPage(1)"'+_E2+'1'+_S2+'/button'+_E2);
      if (winStart > 2) html.push(_S2+'span style="color:#475569;padding:0 4px;"'+_E2+'...'+_S2+'/span'+_E2);
    }
    for (var pg = winStart; pg <= winEnd; pg++) {
      var active = pg === currentPage ? ' active' : '';
      html.push(_S2+'button class="page-btn'+active+'" onclick="renderPage('+pg+')"'+_E2+pg+_S2+'/button'+_E2);
    }
    if (winEnd < totalPages) {
      if (winEnd < totalPages - 1) html.push(_S2+'span style="color:#475569;padding:0 4px;"'+_E2+'...'+_S2+'/span'+_E2);
      html.push(_S2+'button class="page-btn" onclick="renderPage('+totalPages+')"'+_E2+totalPages+_S2+'/button'+_E2);
    }

    /* Next */
    if (currentPage < totalPages) {
      html.push(_S2+'button class="page-btn" onclick="renderPage('+(currentPage+1)+')"'+_E2+'→'+_S2+'/button'+_E2);
    }

    btnsEl.innerHTML = html.join('');
  }

  window.renderPage = renderPage;

  window.filterTable = function() {
    renderPage(1);
  };

  function fmt(n){ return 'S/ ' + parseFloat(n).toLocaleString('es-PE', {minimumFractionDigits:2, maximumFractionDigits:2}); }

  /* ── BAR CHART (SVG puro, scroll horizontal) ─────────────── */
  function buildBarChart() {
    var container = document.getElementById('barChartSvg');
    if (!container || !graficoDatos.length) return;

    var H    = 260;
    var padL = 64, padR = 20, padT = 24, padB = 44;
    var n    = graficoDatos.length;
    /* Cada grupo ocupa al menos 36px — con muchos dias el SVG se hace ancho y el wrapper scrollea */
    var groupW = Math.max(36, Math.floor((container.parentElement.clientWidth - padL - padR) / n));
    var W      = padL + groupW * n + padR;
    var chartW = groupW * n;
    var chartH = H - padT - padB;
    var barW   = Math.max(6, Math.min(18, groupW * 0.38));

    var maxVal = 0;
    graficoDatos.forEach(function(d){
      if (d.ingresos > maxVal) maxVal = d.ingresos;
      if (d.egresos  > maxVal) maxVal = d.egresos;
    });
    if (maxVal === 0) maxVal = 1;

    var p = [];

    p.push('<svg id="barSvg" xmlns="http://www.w3.org/2000/svg" width="'+W+'" height="'+H+'" style="display:block;">');

    /* Grid lines */
    for (var s = 0; s <= 4; s++) {
      var yg   = padT + chartH - (s / 4) * chartH;
      var val  = (s / 4) * maxVal;
      var vlbl = val >= 1000 ? (val/1000).toFixed(1)+'k' : val.toFixed(0);
      p.push('<line x1="'+padL+'" y1="'+yg+'" x2="'+(W-padR)+'" y2="'+yg+'" stroke="rgba(51,65,85,.55)" stroke-width="1"/>');
      p.push('<text x="'+(padL-6)+'" y="'+(yg+4)+'" text-anchor="end" font-size="9" fill="#64748b">'+vlbl+'</text>');
    }

    /* Bars — cada barra lleva data-* para el tooltip */
    graficoDatos.forEach(function(d, i){
      var cx = padL + (i + 0.5) * groupW;
      var hI = (d.ingresos / maxVal) * chartH;
      var hE = (d.egresos  / maxVal) * chartH;
      var xI = cx - barW - 1;
      var xE = cx + 1;

      if (hI > 0) {
        p.push('<rect class="bar-i" x="'+xI+'" y="'+(padT+chartH-hI)+'" width="'+barW+'" height="'+hI+'"'
          +' rx="3" fill="rgba(74,222,128,.82)"'
          +' data-fecha="'+d.fecha+'" data-tipo="Ingreso" data-monto="'+d.ingresos+'"'
          +' style="cursor:pointer;transition:opacity .15s"'
          +' onmouseenter="showTip(event,this)" onmousemove="moveTip(event)" onmouseleave="hideTip()"/>');
      }
      if (hE > 0) {
        p.push('<rect class="bar-e" x="'+xE+'" y="'+(padT+chartH-hE)+'" width="'+barW+'" height="'+hE+'"'
          +' rx="3" fill="rgba(248,113,113,.82)"'
          +' data-fecha="'+d.fecha+'" data-tipo="Egreso" data-monto="'+d.egresos+'"'
          +' style="cursor:pointer;transition:opacity .15s"'
          +' onmouseenter="showTip(event,this)" onmousemove="moveTip(event)" onmouseleave="hideTip()"/>');
      }

      /* Etiqueta de fecha debajo — siempre mostrar todas */
      p.push('<text x="'+cx+'" y="'+(H-6)+'" text-anchor="middle" font-size="9" fill="#64748b">'+d.fecha.slice(0,5)+'</text>');
    });

    /* Legend */
    p.push('<rect x="'+padL+'" y="6" width="10" height="10" rx="2" fill="rgba(74,222,128,.82)"/>');
    p.push('<text x="'+(padL+13)+'" y="15" font-size="10" fill="#94a3b8">Ingresos</text>');
    p.push('<rect x="'+(padL+75)+'" y="6" width="10" height="10" rx="2" fill="rgba(248,113,113,.82)"/>');
    p.push('<text x="'+(padL+88)+'" y="15" font-size="10" fill="#94a3b8">Egresos</text>');

    p.push('</svg>');

    container.style.width = W + 'px';
    container.innerHTML = p.join('').replace(/</g,'\x3C').replace(/>/g,'\x3E');
  }

  /* ── DONUT CHART (SVG puro) ─────────────────────────────── */
  function buildDonutChart() {
    var container = document.getElementById('donutChartSvg');
    if (!container) return;
    var total = totalIngresos + totalEgresos;
    if (total <= 0) return;

    var R = 70, r = 46, cx = 95, cy = 95, size = 190;
    var circ = 2 * Math.PI * R;
    var ingPct = totalIngresos / total;
    var egrPct = 1 - ingPct;
    var ingLen = ingPct * circ;
    var egrLen = egrPct * circ;
    var offset = circ * 0.25;

    var parts = [];
    parts.push('<svg xmlns="http://www.w3.org/2000/svg" width="'+size+'" height="'+size+'">');
    parts.push('<circle cx="'+cx+'" cy="'+cy+'" r="'+R+'" fill="none" stroke="#334155" stroke-width="'+(R-r)+'"/>');
    parts.push('<circle cx="'+cx+'" cy="'+cy+'" r="'+R+'" fill="none" stroke="rgba(74,222,128,.85)" stroke-width="'+(R-r)+'"'
      +' stroke-dasharray="'+ingLen+' '+(circ-ingLen)+'"'
      +' stroke-dashoffset="'+offset+'"'
      +' transform="rotate(-90 '+cx+' '+cy+')"/>');
    parts.push('<circle cx="'+cx+'" cy="'+cy+'" r="'+R+'" fill="none" stroke="rgba(248,113,113,.85)" stroke-width="'+(R-r)+'"'
      +' stroke-dasharray="'+egrLen+' '+(circ-egrLen)+'"'
      +' stroke-dashoffset="'+(offset-ingLen)+'"'
      +' transform="rotate(-90 '+cx+' '+cy+')"/>');
    var pct = (ingPct*100).toFixed(0)+'%';
    parts.push('<text x="'+cx+'" y="'+(cy-6)+'" text-anchor="middle" font-size="18" font-weight="700" fill="#4ade80">'+pct+'</text>');
    parts.push('<text x="'+cx+'" y="'+(cy+12)+'" text-anchor="middle" font-size="9" fill="#64748b">ingresos</text>');
    parts.push('</svg>');

    container.innerHTML = parts.join('').replace(/</g,'\x3C').replace(/>/g,'\x3E');
  }

  /* ── Tooltip functions ───────────────────────────────────── */
  var _tip = null;
  var _S = '\x3C', _E = '\x3E';
  window.showTip = function(e, rect) {
    if (!_tip) _tip = document.getElementById('barTooltip');
    if (!_tip) return;
    var fecha = rect.getAttribute('data-fecha') || '';
    var tipo  = rect.getAttribute('data-tipo')  || '';
    var monto = parseFloat(rect.getAttribute('data-monto') || '0');
    var color = tipo === 'Ingreso' ? '#4ade80' : '#f87171';
    _tip.innerHTML =
      _S+'span style="color:'+color+';font-weight:700;"'+_E+tipo+_S+'/span'+_E+
      _S+'br/'+_E+
      _S+'span style="color:#94a3b8;font-size:.75rem;"'+_E+fecha+_S+'/span'+_E+
      _S+'br/'+_E+
      _S+'span style="font-size:1rem;font-weight:800;"'+_E+fmt(monto)+_S+'/span'+_E;
    _tip.style.display = 'block';
    window.moveTip(e);
  };
  window.moveTip = function(e) {
    if (!_tip || _tip.style.display === 'none') return;
    var x = e.clientX + 14, y = e.clientY - 10;
    if (x + 160 > window.innerWidth)  x = e.clientX - 170;
    if (y + 80  > window.innerHeight) y = e.clientY - 90;
    _tip.style.left = x + 'px';
    _tip.style.top  = y + 'px';
  };
  window.hideTip = function() {
    if (!_tip) _tip = document.getElementById('barTooltip');
    if (_tip) _tip.style.display = 'none';
  };

  /* ── RANGE PICKER (native date inputs) ──────────────────── */
  window.openRangePicker = function() {
    document.getElementById('rpOverlay').style.display = 'flex';
  };

  function initRangePicker() {
    document.getElementById('rpBtnCancel').addEventListener('click', function() {
      document.getElementById('rpOverlay').style.display = 'none';
    });
    document.getElementById('rpBtnApply').addEventListener('click', function() {
      var s = document.getElementById('rpInputStart').value;
      var e = document.getElementById('rpInputEnd').value;
      if (!s || !e) { alert('Selecciona ambas fechas'); return; }
      if (s > e) { alert('La fecha inicio debe ser menor o igual a la fecha fin'); return; }
      window.location.href = '/web/dashboard/caja?periodo=rango&fecha_inicio=' + s + '&fecha_fin=' + e;
    });
    document.getElementById('rpOverlay').addEventListener('click', function(ev) {
      if (ev.target === this) this.style.display = 'none';
    });
  }

  function init() {
    buildBarChart();
    buildDonutChart();
    renderPage(1);
    initRangePicker();
  }

  if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', init); }
  else { init(); }
  window.addEventListener('resize', buildBarChart);

})();
